+                }
+            }
+        };
+
+        checks.push(check);
+    }
+
+    Ok(GuardrailReport {
+        schema_version: policy.schema_version,
+        generated_at_rfc3339: Utc::now().to_rfc3339(),
+        criterion_root: args.criterion_root.display().to_string(),
+        policy_path: args.policy.display().to_string(),
+        total_checks: checks.len(),
+        failures,
+        warnings,
+        pass: failures == 0,
+        checks,
+    })
+}
