+        let args = Args {
+            criterion_root,
+            policy: policy_path,
+            strict_provisional: false,
+        };
+        let report = run(&args).expect("report");
+        assert_eq!(report.failures, 0);
+        assert_eq!(report.warnings, 1);
+        assert!(report.pass);
+        assert_eq!(report.checks[0].status, "warn");
+    }
+}
